defmodule BankServer do
  use GenServer

  def start_link(_) do
    GenServer.start_link(__MODULE__, %{})
  end

  def init(state) do
    :ets.new(:accounts, [:set, :protected, :named_table])
    {:ok, state}
  end

  def deposit(pid, account_id, amount) do
    GenServer.call(pid, {:deposit, account_id, amount})
  end

  def withdraw(pid, account_id, amount) do
    GenServer.call(pid, {:withdraw, account_id, amount})
  end

  def balance(pid, account_id) do
    GenServer.call(pid, {:balance, account_id})
  end

  def handle_call({:deposit, account_id, amount}, _from, state) when amount > 0 do
    case :ets.lookup(:accounts, account_id) do
      [] ->
        :ets.insert(:accounts, {account_id, amount})
        {:reply, {:ok, amount}, state}

      [{account_id, current_balance}] ->
        new_balance = current_balance + amount
        :ets.insert(:accounts, {account_id, new_balance})
        {:reply, {:ok, new_balance}, state}
    end
  end

  def handle_call({:withdraw, account_id, amount}, _from, state) when amount > 0 do
    case :ets.lookup(:accounts, account_id) do
      [] ->
        {:reply, {:error, :insufficient_funds}, state}

      [{account_id, current_balance}] when current_balance < amount ->
        {:reply, {:error, :insufficient_funds}, state}

      [{account_id, current_balance}] ->
        new_balance = current_balance - amount
        :ets.insert(:accounts, {account_id, new_balance})
        {:reply, {:ok, new_balance}, state}
